       scheduled_at, duration_minutes, interview_type, meeting_link, notes]
    );

    // Update application status
    await pool.query(
      `UPDATE job_applications SET status = 'interviewed', updated_at = NOW()
       WHERE job_id = $1 AND candidate_id = $2`,
